import{_ as a,o as t,c as n,ag as i}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Klantportaal","description":"","frontmatter":{},"headers":[],"relativePath":"nl/advanced/customer-portal.md","filePath":"nl/advanced/customer-portal.md"}'),l={name:"nl/advanced/customer-portal.md"};function r(o,e,s,u,d,g){return t(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="klantportaal" tabindex="-1">Klantportaal <a class="header-anchor" href="#klantportaal" aria-label="Permalink to &quot;Klantportaal&quot;">​</a></h1><p>Het klantportaal stelt je klanten in staat om facturen te bekijken en online te betalen via een beveiligde, huisstijl-conforme interface.</p><h2 id="hoe-het-werkt" tabindex="-1">Hoe het werkt <a class="header-anchor" href="#hoe-het-werkt" aria-label="Permalink to &quot;Hoe het werkt&quot;">​</a></h2><p>Wanneer je een factuur verstuurt, wordt een unieke <strong>betaallink</strong> gegenereerd. Wanneer je klant op deze link klikt, wordt deze naar het klantportaal gebracht waar ze kunnen:</p><ol><li><strong>De factuur bekijken</strong> — Alle details, regelitems en totalen zien</li><li><strong>De PDF downloaden</strong> — Een kopie van de factuur krijgen</li><li><strong>Online betalen</strong> — De betaling voltooien via het portaal</li><li><strong>Betaling bevestigen</strong> — Een bankoverschrijving bevestigen</li></ol><h2 id="portaalfuncties" tabindex="-1">Portaalfuncties <a class="header-anchor" href="#portaalfuncties" aria-label="Permalink to &quot;Portaalfuncties&quot;">​</a></h2><h3 id="factuurweergave" tabindex="-1">Factuurweergave <a class="header-anchor" href="#factuurweergave" aria-label="Permalink to &quot;Factuurweergave&quot;">​</a></h3><p>Het portaal toont een overzichtelijke, huisstijl-conforme weergave van de factuur inclusief:</p><ul><li>Je bedrijfslogo en huisstijl</li><li>Factuurnummer en datum</li><li>Regelitems met omschrijvingen en bedragen</li><li>BTW-specificatie</li><li>Totaal verschuldigd bedrag</li><li>Vervaldatum</li></ul><h3 id="betaling" tabindex="-1">Betaling <a class="header-anchor" href="#betaling" aria-label="Permalink to &quot;Betaling&quot;">​</a></h3><p>Klanten kunnen direct via het portaal betalen. Wanneer de betaling is bevestigd, wordt de factuurstatus in je dashboard automatisch bijgewerkt naar <strong>Betaald</strong>.</p><h3 id="huisstijl" tabindex="-1">Huisstijl <a class="header-anchor" href="#huisstijl" aria-label="Permalink to &quot;Huisstijl&quot;">​</a></h3><p>Het klantportaal gebruikt je bedrijfshuisstijl:</p><ul><li>Bedrijfslogo</li><li>Accentkleur</li><li>Bedrijfsinformatie</li></ul><p>Dit creëert een professionele, consistente ervaring voor je klanten.</p><h2 id="toegangsbeveiliging" tabindex="-1">Toegangsbeveiliging <a class="header-anchor" href="#toegangsbeveiliging" aria-label="Permalink to &quot;Toegangsbeveiliging&quot;">​</a></h2><p>Elke portaallink is:</p><ul><li><strong>Uniek</strong> — Gegenereerd per factuur</li><li><strong>Tokengebaseerd</strong> — Beveiligd met een uniek toegangstoken</li><li><strong>Factuurspecifiek</strong> — Toont alleen de specifieke factuur</li></ul><p>Klanten hebben geen MyCompanyDesk-account nodig om facturen te bekijken en te betalen.</p><h2 id="klantgebeurtenissen-bijhouden" tabindex="-1">Klantgebeurtenissen bijhouden <a class="header-anchor" href="#klantgebeurtenissen-bijhouden" aria-label="Permalink to &quot;Klantgebeurtenissen bijhouden&quot;">​</a></h2><p>MyCompanyDesk houdt klantinteracties met het portaal bij:</p><ul><li>Wanneer de klant de factuur opent</li><li>Wanneer ze de PDF downloaden</li><li>Wanneer ze een betaling initieren</li><li>Wanneer de betaling is bevestigd</li></ul><p>Dit helpt je om klantbetrokkenheid te begrijpen en effectief op te volgen.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Voeg een persoonlijke notitie toe aan je factuur-e-mail om portaalgebruik aan te moedigen</li><li>Het portaal werkt op alle apparaten — mobiel, tablet en desktop</li><li>Betalingsbevestigingen worden naar zowel jou als de klant gestuurd</li><li>Bekijk de klantgebeurtenisgeschiedenis op de factuurdetailpagina om portaalinteracties te zien</li></ul>',25)])])}const p=a(l,[["render",r]]);export{h as __pageData,p as default};
